import React, {useEffect, useState} from 'react';
import axios from "axios";
import ImageProvider from "./imageProvider";
import RarityTable from "./RarityTable";
import MultiSelect from "react-multi-select-component/src/multi-select/index";
import { Select, Typography } from 'antd';

const { Title } = Typography;
const Search = (props) => {
    const [multiSelections, setMultiSelections] = useState([]);
    const [options, setOptions] = useState([]);
    const [contentTags, setContentTags] = useState([]);
    const [optionTags, setOptionTags] = useState([]);
    const [searchResult, setSearchResult] = useState([]);


    const [modalSearchShow, setModalSearchShow] = useState(false);
    const [nextFunction, setNextFunction] = useState();
    const [pageNumber, setPageNumber] = useState();
    const [noMatchingWording, setNoMatchingWording] = useState();
    const [hasMore, setHasMore] = useState(true);

    // Fetch images on component mount
    useEffect(() => {
        getAllTags()
    }, [])

    const getTableTags = (tags) => {
        if (tags) {
            const tableTags1 = []
            const tableTags2 = []
            const tableTags3 = []
            const tableTagsTotal = []
            for (let i = 0; i < 30; i++) tableTags1.push(<div key={i}><a>{tags[i].name} ({tags[i].count})</a><br/> </div>)
            for (let j = 30; j < 60; j++) tableTags2.push(<div key={j}><a>{tags[j].name} ({tags[j].count})</a><br/> </div>)
            for (let k = 60; k < tags.length; k++) tableTags3.push(<div key={k}><a>{tags[k].name} ({tags[k].count})</a><br/> </div>)
            tableTagsTotal.push(tableTags1)
            tableTagsTotal.push(tableTags2)
            tableTagsTotal.push(tableTags3)
            setContentTags(tableTagsTotal);
        }
    }

    const getOptionTags = (tags) => {
        if (tags) {
            const optionTagsResult = []
            for (let i = 0; i < tags.length; i++) optionTagsResult.push({value: tags[i].name, key:"tag-key-name"+tags[i].name})
            for (let j = 0; j < 10000; j++) optionTagsResult.push({value: j+"",key:"cbit-number-key"+j})
            setOptionTags(optionTagsResult);
        }
    }

    // Fetch images on component mount
    useEffect(() => {
        setNoMatchingWording(<p></p>)
        if (multiSelections.length === 0) {
            setSearchResult([])
            setNextFunction({})
            setPageNumber(0)
            setHasMore(true)
        } else {
            if (isNaN(multiSelections[0])) {
                setSearchResult([])
                setNextFunction(getCBitsByTags)
                setPageNumber(0)
                setHasMore(true)
                getCBitsByTags()
            } else {
                setSearchResult([])
                setNextFunction({})
                setPageNumber(0)
                setHasMore(false)
                getCBitsByNumbers()
            }
        }
    }, [multiSelections])

    // API endpoint
    const endpoint = "https://backend.cardanobits.art:9364"
    // Fetch Images from functions
    const getAllTags = () => {
        axios(endpoint + "/tags").then(res => {
            setOptions(res.data)
            getTableTags(res.data)
            getOptionTags(res.data)
        })
    }

    // Fetch Images from functions
    const getCBitsByTags = () => {
        const arrayOfTags = multiSelections.map(a => a);
        axios(endpoint + `/tags/cardanobits?tags=${arrayOfTags}&pageNumber=${0}`).then(res => {
            if (res.data.length === 0) {
                setSearchResult([])
                setPageNumber(0)
                setNoMatchingWording(<p> No CBits matching your search.</p>)
            } else {
                setPageNumber(pageNumber + 1)
                setSearchResult([...res.data])
            }
        })
    }
    const getCBitsByNumbers = () => {
        const arrayOfTags = multiSelections.map(a => a)
        axios(endpoint + `/cardanobits/ids?ids=${arrayOfTags}`).then(res => {
            if (res.data.length === 0) {
                setSearchResult([])
            } else {
                setSearchResult([...res.data])
            }
        })
    }
    function handleChange(value) {
        console.log(`selected ${value}`);
        setMultiSelections(value)
    }
    return (
        <>
            <section className="swag" id="collection">
                <div className="container text-center">
                    <div className="row">
                        <div className="col-md-12">
                            <h1 className="arrow">
                                Our <span>Collection</span>
                            </h1>
                            <p>Only 10.000 CardanoBits were minted, using a <a
                                href="https://cardanoscan.io/tokenPolicy/1131301ad4b3cb7deaddbc8f03f77189082a5738c0167e1772233097">time-locked
                                policy</a>. Each one is unique, and generated with a mix of art pieces and computer
                                algorithms. Check the <a href="#collection"
                                                         onClick={() => setModalSearchShow(true)}>tags/types</a> table!
                            </p>
                            <RarityTable
                                tags={contentTags}
                                show={modalSearchShow}
                                onHide={() => setModalSearchShow(false)}
                            />
                        </div>
                    </div>
                    <div className="row">
                        <div className="col-md-12">
                            <br/>
                            <Select
                                className="search-bar"
                                mode="multiple"
                                style={{ width: '100%' }}
                                placeholder="Please select"
                                onChange={handleChange}
                                options={optionTags}
                            />
                            <br/>
                            <br/>

                        </div>
                    </div>

                    <div className="row ">
                        <br/>
                        <div className="col-md-12">
                            <ImageProvider searchResult={searchResult} multiSelections={multiSelections} hasMore={hasMore} />
                            {noMatchingWording}
                        </div>
                    </div>
                </div>

            </section>

        </>
    );
};

export default Search;
